# CORRECT — asyncpg is async; yields to event loop during I/O
@app.get("/users/{id}")
async def get_user(id: int):
    async with pool.acquire() as conn:
        row = await conn.fetchrow("SELECT * FROM users WHERE id = $1", id)
        return dict(row)

# FastAPI dispatches def endpoints to thread pool — safe for sync drivers
@app.get("/users/{id}")
def get_user_sync(id: int):
    with psycopg2.connect(DSN) as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM users WHERE id = %s", (id,))
        return cursor.fetchone()

from sqlalchemy import select

async def get_user_by_id(db: AsyncSession, user_id: int) -> User | None:
    result = await db.execute(
        select(User).where(User.id == user_id)
    )
    return result.scalar_one_or_none()

async def get_user_by_email(db: AsyncSession, email: str) -> User | None:
    result = await db.execute(
        select(User).where(User.email == email)
    )
    return result.scalar_one_or_none()
